sql:
SELECT COUNT(DISTINCT date) AS total_active_days
FROM air_traffic_control
WHERE atc_status = 'operational' AND date LIKE '2023-01%';

external_knowledge:
- "carriers" refers to the airlines;
- "departure points" refer to the origin airports;
- "takeoffs" are synonymous with the flights;
- "how many" refers to the count of flights.

sql:
SELECT DISTINCT f.flight_number 
FROM flights f
JOIN flight_delays fd ON f.flight_id = fd.flight_id;

